#[test]
fn test_full_compilation_benchmark() {
    info!("TEST START: test_full_compilation_benchmark");
    info!("INPUT: run_compilation_benchmark()");
    let result = run_compilation_benchmark().unwrap();
    info!("RESULT: score={}, debug={}ms, release={}ms, incremental={}ms, rustc={}",
          result.score, result.debug_build_ms, result.release_build_ms,
          result.incremental_build_ms, result.rustc_version);
    assert!(result.score > 0.0);
    assert!(result.release_build_ms > 0);
    assert!(result.release_build_ms > result.debug_build_ms / 2);  // Release usually slower
    info!("VERIFY: All metrics positive and reasonable");
    info!("TEST PASS: test_full_compilation_benchmark");
}
